 42→export const useAppStore = create<AppStoreState>((set, get) => ({
 43→  isBootstrapping: true,
 44→  errorMessage: null,
 45→  appState: null,
 46→  draftSelections: {},
 47→  subscription: emptySubscriptionSnapshot,
 48→
 49→  bootstrap: async () => {
 50→    try {
 51→      set({ isBootstrapping: true, errorMessage: null });
 52→      const appState = await appRepository.loadState();
 53→      set({ appState, isBootstrapping: false });
 54→      await refreshSubscription(set, get().subscription);
 55→    } catch (error) {
 56→      set({
 57→        isBootstrapping: false,
 58→        errorMessage: error instanceof Error ? error.message : 'Failed to bootstrap Grock.',
 59→      });
 60→    }
 61→  },
 62→
 63→  refresh: async () => {
 64→    try {
 65→      const appState = await appRepository.loadState();
 66→      set({ appState, errorMessage: null });
 67→      await refreshSubscription(set, get().subscription);
 68→    } catch (error) {
 69→      set({ errorMessage: error instanceof Error ? error.message : 'Refresh failed.' });
 70→    }
 71→  },
 72→
 73→  completeOnboarding: async input => {
 74→    const appState = await appRepository.completeOnboarding(input);
 75→    set({ appState, errorMessage: null });
 76→  },
 77→
 78→  updateUserName: async name => {
 79→    const appState = await appRepository.updateUserName(name);
 80→    set({ appState, errorMessage: null });
 81→  },
 82→
 83→  addCategory: async (name, emoji) => {
 84→    const appState = await appRepository.addCategory(name, emoji);
 85→    set({ appState, errorMessage: null });
 86→  },
 87→
 88→  addItem: async input => {
 89→    const appState = await appRepository.addItem(input);
 90→    set({ appState, errorMessage: null });
 91→  },
 92→
 93→  createCart: async input => {
 94→    const appState = await appRepository.createCart(input);
 95→    set({ appState, errorMessage: null, draftSelections: {} });
 96→  },
 97→
 98→  toggleCartItemFulfillment: async (cartId, cartItemId) => {
 99→    const appState = await appRepository.toggleCartItemFulfillment(cartId, cartItemId);
100→    set({ appState, errorMessage: null });
101→  },
102→
103→  advanceCartStatus: async cartId => {
104→    const appState = await appRepository.advanceCartStatus(cartId);
105→    set({ appState, errorMessage: null });
106→  },
107→
108→  deleteItem: async itemId => {
109→    const appState = await appRepository.deleteItem(itemId);
110→    const draftSelections = { ...get().draftSelections };
111→    delete draftSelections[itemId];
112→    set({ appState, draftSelections, errorMessage: null });
113→  },
114→
115→  toggleDraftItem: itemId => {
116→    const current = get().draftSelections;
117→    if (current[itemId]) {
118→      const next = { ...current };
119→      delete next[itemId];
120→      set({ draftSelections: next });
121→      return;
122→    }
123→
124→    set({ draftSelections: { ...current, [itemId]: 1 } });
125→  },
126→
127→  setDraftQuantity: (itemId, quantity) => {
128→    const safeQuantity = Math.max(1, quantity);
129→    set({
130→      draftSelections: {
131→        ...get().draftSelections,
132→        [itemId]: safeQuantity,
133→      },
134→    });
135→  },
136→
137→  clearDraftSelections: () => set({ draftSelections: {} }),
138→
139→  resetApp: async () => {
140→    const appState = await appRepository.resetState();
141→    set({
142→      appState,
143→      draftSelections: {},
144→      errorMessage: null,
145→    });
146→  },
147→}));
