313→export function computeCartTotal(vault: Vault, cart: Cart): number {
314→  return cart.cartItems.reduce((total, cartItem) => {
315→    if (cart.status !== 'planning' && cartItem.isSkippedDuringShopping) {
316→      return total;
317→    }
318→
319→    const item = getItemById(vault, cartItem.itemId);
320→    const fallbackPrice = item ? getCurrentPrice(item, cartItem.plannedStore) ?? 0 : 0;
321→    const price =
322→      cart.status !== 'planning'
323→        ? cartItem.actualPrice ?? cartItem.plannedPrice ?? fallbackPrice
324→        : cartItem.plannedPrice ?? fallbackPrice;
325→
326→    const quantity = cart.status === 'planning'
327→      ? cartItem.quantity
328→      : cartItem.actualQuantity ?? cartItem.quantity;
329→
330→    return total + price * quantity;
331→  }, 0);
332→}
