11→export function useAnimatedEntrance(index: number, delayMs = 60) {
12→  const opacity = useSharedValue(0);
13→  const translateY = useSharedValue(12);
14→
15→  useEffect(() => {
16→    const delay = index * delayMs;
17→    opacity.value = withDelay(delay, withSpring(1, motion.gentle));
18→    translateY.value = withDelay(delay, withSpring(0, motion.gentle));
19→  }, [index, delayMs, opacity, translateY]);
20→
21→  const animatedStyle = useAnimatedStyle(() => ({
22→    opacity: opacity.value,
23→    transform: [{ translateY: translateY.value }],
24→  }));
25→
26→  return animatedStyle;
27→}
